INSERT INTO products (id, name, description, long_description, price, currency, category, artisan, country, image, tags, in_stock) VALUES
('hand-thrown-clay-bowl', 'Hand-Thrown Clay Bowl', 'Traditional terracotta bowl with hand-painted geometric patterns inspired by Roma motifs.', 'This beautiful hand-thrown clay bowl is crafted using techniques passed down through generations of Roma potters in central Serbia. Each piece is individually shaped on a traditional wheel, dried slowly in open air, and fired in a wood-burning kiln. The geometric patterns are hand-painted using natural pigments, making every bowl truly one-of-a-kind.', 45.00, 'EUR', 'Pottery & Ceramics', 'Dragan M.', 'Serbia', 'https://images.unsplash.com/photo-1565193566173-7a0ee3dbe261?w=600&h=600&fit=crop', ARRAY['handmade','pottery','traditional'], true),
('woven-kilim-runner', 'Woven Kilim Runner', 'Handwoven wool kilim with traditional Balkans diamond pattern in natural dyes.', 'This stunning kilim runner is handwoven on a traditional loom by skilled textile artisans in Kosovo. Made from locally sourced wool and colored with natural plant-based dyes, it features the iconic diamond pattern found throughout Balkans weaving traditions. Each runner takes approximately two weeks to complete.', 120.00, 'EUR', 'Textiles & Weaving', 'Fatima H.', 'Kosovo', 'https://images.unsplash.com/photo-1600166898405-da9535204843?w=600&h=600&fit=crop', ARRAY['handwoven','textile','wool'], true),
('filigree-silver-pendant', 'Filigree Silver Pendant', 'Delicate sterling silver filigree pendant with traditional Roma swirl design.', 'This exquisite pendant showcases the ancient art of silver filigree, a technique perfected by Roma silversmiths over centuries.', 85.00, 'EUR', 'Jewelry & Metalwork', 'Elena V.', 'North Macedonia', 'https://images.unsplash.com/photo-1611652022419-a9419f74343d?w=600&h=600&fit=crop', ARRAY['silver','filigree','jewelry'], true),
('carved-walnut-cutting-board', 'Carved Walnut Cutting Board', 'Hand-carved serving board from Bosnian walnut with decorative border pattern.', 'Crafted from a single piece of aged Bosnian walnut, this serving and cutting board features a delicately carved border inspired by traditional Roma woodcarving motifs.', 55.00, 'EUR', 'Woodwork & Carving', 'Alen K.', 'Bosnia', 'https://images.unsplash.com/photo-1588165171080-c89acfa5ee83?w=600&h=600&fit=crop', ARRAY['wood','walnut','kitchen'], true),
('embroidered-linen-tablecloth', 'Embroidered Linen Tablecloth', 'Hand-embroidered linen tablecloth with traditional floral patterns in red and gold.', 'This luxurious tablecloth is crafted from natural linen and adorned with hand-embroidered floral patterns.', 95.00, 'EUR', 'Textiles & Weaving', 'Mira S.', 'Albania', 'https://images.unsplash.com/photo-1594040226829-7f251ab46d80?w=600&h=600&fit=crop', ARRAY['embroidery','linen','tablecloth'], true),
('copper-coffee-pot-cezve', 'Copper Coffee Pot (Cezve)', 'Hand-hammered copper cezve for traditional Balkans coffee with brass handle.', 'This hand-hammered copper cezve is an essential piece of Balkans coffee culture.', 40.00, 'EUR', 'Jewelry & Metalwork', 'Marko D.', 'Montenegro', 'https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=600&h=600&fit=crop', ARRAY['copper','coffee','handmade'], true),
('leather-satchel-bag', 'Leather Satchel Bag', 'Vegetable-tanned leather satchel with hand-stitched details and brass buckle.', 'This timeless satchel is made from vegetable-tanned cowhide leather.', 150.00, 'EUR', 'Leather Goods', 'Besnik Q.', 'Albania', 'https://images.unsplash.com/photo-1548036328-c9fa89d128fa?w=600&h=600&fit=crop', ARRAY['leather','bag','handstitched'], true),
('ajvar-homemade-spread', 'Homemade Ajvar Spread', 'Traditional roasted red pepper and eggplant spread made from a family recipe.', 'This rich, smoky ajvar is made from hand-roasted red peppers and eggplant.', 12.00, 'EUR', 'Food & Spices', 'Jovana P.', 'Serbia', 'https://images.unsplash.com/photo-1563822249366-3efb23b8e0c9?w=600&h=600&fit=crop', ARRAY['food','ajvar','traditional'], true),
('ceramic-espresso-set', 'Ceramic Espresso Cup Set', 'Set of 4 hand-glazed ceramic espresso cups with saucers in earthy tones.', 'This set of four espresso cups with matching saucers is hand-thrown and glazed.', 60.00, 'EUR', 'Pottery & Ceramics', 'Samir T.', 'North Macedonia', 'https://images.unsplash.com/photo-1514228742587-6b1558fcca3d?w=600&h=600&fit=crop', ARRAY['ceramic','espresso','set'], true),
('hand-carved-wooden-flute', 'Hand-Carved Wooden Flute', 'Traditional kaval flute carved from plum wood with decorative burnt patterns.', 'This traditional kaval flute is hand-carved from aged plum wood.', 35.00, 'EUR', 'Woodwork & Carving', 'Ismet B.', 'Kosovo', 'https://images.unsplash.com/photo-1507838153414-b4b713384a76?w=600&h=600&fit=crop', ARRAY['music','flute','woodcarving'], true),
('balkans-spice-collection', 'Balkans Spice Collection', 'Curated set of 6 traditional Balkans spice blends in handmade ceramic jars.', 'This collection brings together six signature spice blends used across the Western Balkans.', 48.00, 'EUR', 'Food & Spices', 'Amina R.', 'Bosnia', 'https://images.unsplash.com/photo-1596040033229-a9821ebd058d?w=600&h=600&fit=crop', ARRAY['spices','collection','ceramic'], true),
('leather-journal-embossed', 'Embossed Leather Journal', 'Hand-bound journal with embossed Roma sun motif and recycled cotton pages.', 'This elegant journal features a cover of vegetable-tanned leather embossed with a traditional Roma sun motif.', 38.00, 'EUR', 'Leather Goods', 'Liridon G.', 'Kosovo', 'https://images.unsplash.com/photo-1544816155-12df9643f363?w=600&h=600&fit=crop', ARRAY['leather','journal','handbound'], true)
