('fatima-dogsitter-pristina', 'Fatima K.', 'Professional Pet Sitter', 'Loving pet care including dog walking and house sitting.', 'Fatima has been caring for pets professionally for 5 years.', 'Pet Care', 10, 15, 'EUR', 5.0, 63, 'Pristina', 'Kosovo', 'https://images.unsplash.com/photo-1587300003388-59208cc962cb?w=400&h=400&fit=crop', ARRAY['Verified','Top Rated'], true, 'Under 30 min', 198),
('alen-electrician-sarajevo', 'Alen M.', 'Certified Electrician', 'Certified electrician offering residential and commercial electrical work.', 'Alen is a fully certified electrician with 12 years of experience.', 'Home Repair', 30, 40, 'EUR', 4.8, 52, 'Sarajevo', 'Bosnia', 'https://images.unsplash.com/photo-1621905252507-b35492cc74b4?w=400&h=400&fit=crop&crop=face', ARRAY['Verified','Certified'], true, 'Under 2 hours', 245),
('mira-cleaning-tirana', 'Mira B.', 'Professional House Cleaner', 'Thorough, reliable house cleaning and deep cleaning services.', 'Mira runs a small cleaning team providing residential cleaning services across Tirana.', 'Cleaning', 12, 25, 'EUR', 4.9, 94, 'Tirana', 'Albania', 'https://images.unsplash.com/photo-1581578731548-c64695cc6952?w=400&h=400&fit=crop', ARRAY['Verified','Eco-Friendly'], true, 'Under 1 hour', 410),
('stefan-handyman-skopje', 'Stefan N.', 'General Handyman', 'Jack-of-all-trades handyman for furniture assembly and repairs.', 'Stefan handles a wide range of home improvement tasks.', 'Home Repair', 18, 20, 'EUR', 4.7, 41, 'Skopje', 'North Macedonia', 'https://images.unsplash.com/photo-1556761175-5973dc0f32e7?w=400&h=400&fit=crop&crop=face', ARRAY['Verified'], true, 'Under 3 hours', 156),
('elena-tutor-belgrade', 'Elena R.', 'Language & Music Tutor', 'Native Serbian speaker offering language tutoring.', 'Elena is a qualified language teacher offering one-on-one and small group lessons.', 'Tutoring & Lessons', 15, NULL, 'EUR', 5.0, 38, 'Belgrade', 'Serbia', 'https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=400&h=400&fit=crop&crop=face', ARRAY['Verified','Top Rated'], true, 'Under 2 hours', 89),
('besnik-moving-tirana', 'Besnik L.', 'Moving & Delivery Service', 'Reliable moving and delivery service with a van.', 'Besnik and his team provide professional moving services across Tirana.', 'Transport & Moving', 20, 35, 'EUR', 4.6, 29, 'Tirana', 'Albania', 'https://images.unsplash.com/photo-1600880292203-757bb62b4baf?w=400&h=400&fit=crop&crop=face', ARRAY['Verified'], true, 'Under 3 hours', 178),
('jovana-hairdresser-podgorica', 'Jovana S.', 'Mobile Hairdresser & Stylist', 'Professional hairdresser offering cuts, coloring, and styling.', 'Jovana brings the salon to you with 8 years of experience.', 'Beauty & Wellness', 15, 12, 'EUR', 4.9, 56, 'Podgorica', 'Montenegro', 'https://images.unsplash.com/photo-1560066984-138dadb4c035?w=400&h=400&fit=crop', ARRAY['Verified','Top Rated'], true, 'Under 1 hour', 267),
('marko-it-belgrade', 'Marko V.', 'Computer & Phone Repair', 'Fast, affordable computer and smartphone repairs.', 'Marko is a skilled IT technician offering tech support.', 'IT & Digital', 20, 15, 'EUR', 4.8, 44, 'Belgrade', 'Serbia', 'https://images.unsplash.com/photo-1531297484001-80022131f5a1?w=400&h=400&fit=crop', ARRAY['Verified'], true, 'Under 2 hours', 203),
('amina-catering-sarajevo', 'Amina H.', 'Traditional Balkans Catering', 'Authentic home-cooked Balkans catering for events.', 'Amina provides catering services featuring traditional Bosnian and Roma cuisine.', 'Events & Catering', 0, 80, 'EUR', 5.0, 31, 'Sarajevo', 'Bosnia', 'https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=400&h=400&fit=crop', ARRAY['Verified','Top Rated'], true, 'Under 3 hours', 95),
('liridon-dogwalker-pristina', 'Liridon G.', 'Dog Walker & Pet Trainer', 'Energetic dog walker and basic obedience trainer.', 'Liridon is passionate about dogs and offers daily walking services.', 'Pet Care', 8, 10, 'EUR', 4.7, 22, 'Pristina', 'Kosovo', 'https://images.unsplash.com/photo-1601758228041-f3b2795255f1?w=400&h=400&fit=crop', ARRAY['Verified'], true, 'Under 1 hour', 134),
('ana-tailor-skopje', 'Ana T.', 'Seamstress & Tailor', 'Skilled seamstress offering clothing alterations.', 'Ana has been sewing for over 20 years.', 'Beauty & Wellness', 12, 8, 'EUR', 4.9, 47, 'Skopje', 'North Macedonia', 'https://images.unsplash.com/photo-1556740758-90de940a6755?w=400&h=400&fit=crop', ARRAY['Verified','Top Rated'], true, 'Under 2 hours', 189)
